customCss:
.mfp-intake{--in-primary:#2563eb;--in-ink:#0f172a;--in-muted:#64748b;--in-border:#e2e8f0;font-family:'Inter',system-ui,-apple-system,'Segoe UI',sans-serif;color:var(--in-ink);width:100%;max-width:1040px;margin:0 auto;padding:24px;background:transparent}
.mfp-intake .in-card{display:grid;grid-template-columns:240px 1fr;background:#fff;border:1px solid var(--in-border);border-radius:20px;box-shadow:0 10px 30px rgba(2,32,71,.08);overflow:hidden}
.mfp-intake .in-rail{background:linear-gradient(180deg,#f0f6ff,#eaf1ff);padding:28px 22px;display:flex;flex-direction:column;gap:26px;border-right:1px solid var(--in-border)}
.mfp-intake .in-brand{display:flex;gap:12px;align-items:flex-start}
.mfp-intake .in-logo{width:40px;height:40px;border-radius:11px;background:var(--in-primary);color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px;box-shadow:0 4px 12px rgba(37,99,235,.4);flex:0 0 auto}
.mfp-intake .in-brand-name{font-weight:700;font-size:15px;color:var(--in-ink)}
.mfp-intake .in-brand-sub{font-size:12.5px;color:var(--in-muted);margin-top:2px}
.mfp-intake .in-steps{display:flex;flex-direction:column;gap:4px}
.mfp-intake .in-step{display:flex;align-items:center;gap:12px;padding:9px 10px;border-radius:10px;color:var(--in-muted);font-weight:600;font-size:14px}
.mfp-intake .in-step .in-step-dot{width:30px;height:30px;border-radius:50%;background:#fff;border:1px solid var(--in-border);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;flex:0 0 auto}
.mfp-intake .in-step.is-active{color:var(--in-primary)}
.mfp-intake .in-step.is-active .in-step-dot{background:var(--in-primary);color:#fff;border-color:var(--in-primary);box-shadow:0 3px 8px rgba(37,99,235,.4)}
.mfp-intake .in-theme-chip{margin-top:auto;align-self:flex-start;border:1px solid #c7dbff;background:#fff;border-radius:999px;padding:7px 14px;font-size:13px;color:var(--in-primary);font-weight:600}
.mfp-intake .in-main{padding:34px 38px}
.mfp-intake .in-eyebrow{color:var(--in-primary);font-weight:700;font-size:12px;letter-spacing:.08em;text-transform:uppercase}
.mfp-intake .in-title{margin:6px 0 22px;font-size:24px;font-weight:800;color:var(--in-ink)}
.mfp-intake .in-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}
.mfp-intake .in-actions{display:flex;justify-content:flex-end;margin-top:26px}
.mfp-intake .in-submit{background:var(--in-primary);color:#fff;border:none;border-radius:10px;padding:12px 22px;font-weight:600;font-size:15px;cursor:pointer;box-shadow:0 6px 16px rgba(37,99,235,.35)}
.mfp-intake .in-submit:hover{background:#1d4ed8}
.mfp-intake .mf-field-group{margin-bottom:16px}
.mfp-intake input,.mfp-intake select,.mfp-intake textarea{width:100%;border:1px solid var(--in-border);border-radius:9px;padding:11px 13px;font-size:14px;background:#fff;color:var(--in-ink);box-sizing:border-box}
.mfp-intake input::placeholder,.mfp-intake textarea::placeholder{color:#94a3b8}
.mfp-intake input:focus,.mfp-intake select:focus,.mfp-intake textarea:focus{outline:none;border-color:var(--in-primary);box-shadow:0 0 0 3px rgba(37,99,235,.15)}
.mfp-intake label,.mfp-intake .mf-field-label{font-size:13px;font-weight:600;color:#334155;margin-bottom:6px;display:block}
@media(max-width:720px){.mfp-intake .in-card{grid-template-columns:1fr}.mfp-intake .in-grid{grid-template-columns:1fr}.mfp-intake .in-rail{flex-direction:row;flex-wrap:wrap;border-right:none;border-bottom:1px solid var(--in-border)}}

